package out

import (
	"encoding/json"
	"net/http"
	"strings"
)

// ProblemDetails is a JSON object that describes an error.
// https://datatracker.ietf.org/doc/html/rfc9457
type ProblemDetails struct {
	// Type is a URI reference [RFC3986] that identifies the problem type.
	Type string `json:"type,omitempty"`
	// StatusCode is the HTTP status code generated by the origin server for this occurrence of the problem.
	StatusCode int `json:"statuscode"`
	// Title contains a short, human-readable summary of the problem.
	Title string `json:"title"`
	// Detail contains a human-readable explanation specific to this occurrence of the problem.
	Detail string `json:"detail,omitempty"`
	// Instance is a URI reference that identifies the specific occurrence of the problem.
	Instance string `json:"instance,omitempty"`

	// Extensions is a map of additional information about the problem. They will be inlined in the JSON response.
	Extensions map[string]any `json:"-"`
	// Cause is the underlying error that caused this problem. This will be logged.
	Cause error `json:"-"`

	Headers http.Header    `json:"-"`
	Cookies []*http.Cookie `json:"-"`
}

func (p *ProblemDetails) UnmarshalJSON(bytes []byte) error {
	var all map[string]any
	if err := json.Unmarshal(bytes, &all); err != nil {
		return err
	}

	if v, ok := all["type"].(string); ok {
		p.Type = v
	}
	delete(all, "type")

	if v, ok := all["status"].(float64); ok {
		p.StatusCode = int(v)
	}
	delete(all, "status")

	if v, ok := all["title"].(string); ok {
		p.Title = v
	}
	delete(all, "title")

	if v, ok := all["detail"].(string); ok {
		p.Detail = v
	}
	delete(all, "detail")

	if v, ok := all["instance"].(string); ok {
		p.Instance = v
	}
	delete(all, "instance")

	if len(all) > 0 {
		p.Extensions = all
	}

	return nil
}

func (p ProblemDetails) MarshalJSON() ([]byte, error) {
	m := make(map[string]any)

	if p.Type != "" {
		m["type"] = p.Type
	}
	m["status"] = p.StatusCode
	m["title"] = p.Title
	if p.Detail != "" {
		m["detail"] = p.Detail
	}
	if p.Instance != "" {
		m["instance"] = p.Instance
	}

	for k, v := range p.Extensions {
		m[k] = v
	}

	return json.Marshal(m)
}

func (p ProblemDetails) Unwrap() error {
	return p.Cause
}

func (p ProblemDetails) Error() string {
	s := strings.Builder{}
	s.WriteString(p.Title)
	if p.Detail != "" {
		s.WriteString(": ")
		s.WriteString(p.Detail)
	}
	if p.Cause != nil {
		s.WriteString("; ")
		s.WriteString(p.Cause.Error())
	}
	return s.String()
}
